fn solve(nums: Vec<i64>, target: i64) -> i64 {
    let n = nums.len();
    if n == 0 {
        return if target == 0 { 0 } else { -1 };
    }

    let n_l = n / 2;
    let l = &nums[0..n_l];
    let r = &nums[n_l..n];
    let n_r = n - n_l;

    // Map L_XOR_sum -> max_size
    let mut map_l: HashMap<i64, i64> = HashMap::new();

    // Initialize with empty set: XOR sum 0, size 0
    map_l.insert(0, 0);

    // 1. Process Left Half (L)
    // Iterate through all 2^N_L subsets
    for i in 1..(1 << n_l) {
        let mut current_xor = 0i64;
        let mut current_size = 0i64;

        for j in 0..n_l {
            if (i >> j) & 1 == 1 {
                current_xor ^= l[j];
                current_size += 1;
            }
        }

        // Store the maximum size found for this XOR sum
        map_l.entry(current_xor)
             .and_modify(|e| *e = (*e).max(current_size))
             .or_insert(current_size);
    }

    // 2. Process Right Half (R) and find max combined size
    let mut max_total_size = -1i64;

    // Iterate through all 2^N_R subsets
    for i in 0..(1 << n_r) {
        let mut current_xor_r = 0i64;
        let mut current_size_r = 0i64;

        for j in 0..n_r {
            if (i >> j) & 1 == 1 {
                current_xor_r ^= r[j];
                current_size_r += 1;
            }
        }

        // We need X_L ^ X_R = target, so X_L = target ^ X_R
        let required_xor_l = target ^ current_xor_r;

