use std::collections::HashMap;

fn solve(nums: Vec<i64>, target: i64) -> i64 {
    let n = nums.len();
    if n == 0 {
        return if target == 0 { 0 } else { -1 };
    }

    // Calculate total XOR sum X
    let total_xor: i64 = nums.iter().fold(0, |acc, &x| acc ^ x);

    // Target XOR sum T required from the removed set R
    let t = total_xor ^ target;

    // Split nums into two halves A and B
    let n_a = n / 2;
    let a = &nums[0..n_a];
    let b = &nums[n_a..n];
    let n_b = n - n_a;

    // Map A: XOR sum -> minimum subset size using elements from A
    // Initialize map_a with the empty set (XOR sum 0, size 0)
    let mut map_a: HashMap<i64, i64> = HashMap::new();
    map_a.insert(0, 0);

    // Generate all subset XOR sums and their minimum sizes for A
    let limit_a = 1 << n_a;
    for i in 0..limit_a {
        let mut current_xor = 0;
        let mut current_size = 0;

        for j in 0..n_a {
            if (i >> j) & 1 == 1 {
                current_xor ^= a[j];
                current_size += 1;
            }
        }

        // Update map_a, keeping only the minimum size for any given XOR sum
        let entry = map_a.entry(current_xor).or_insert(n as i64 + 1);
        *entry = (*entry).min(current_size);
    }


    // Map B: XOR sum -> minimum subset size using elements from B
    let mut map_b: HashMap<i64, i64> = HashMap::new();
    map_b.insert(0, 0);

    // Generate all subset XOR sums and their minimum sizes for B
    let limit_b = 1 << n_b;
    for i in 0..limit_b {
        let mut current_xor = 0;
        let mut current_size = 0;

        for j in 0..n_b {
            if (i >> j) & 1 == 1 {
                current_xor ^= b[j];
                current_size += 1;
            }
        }

        let entry = map_b.entry(current_xor).or_insert(n as i64 + 1);
        *entry = (*entry).min(current_size);
    }

    // Combine results: Find min(|R_A| + |R_B|) such that XOR(R_A) ^ XOR(R_B) = T
    let mut min_r: i64 = n as i64 + 1;

    for (&xor_a, &size_a) in map_a.iter() {
        // We need xor_b = T ^ xor_a
        let required_xor_b = t ^ xor_a;

        // Check if this required XOR sum exists in Map B
        if let Some(&size_b) = map_b.get(&required_xor_b) {
            let total_size = size_a + size_b;
            min_r = min_r.min(total_size);
        }
    }

    // Return result
    if min_r > n as i64 {
        -1
    } else {
        min_r
    }
}

