fn solve(nums: Vec<i64>, target: i64) -> i64 {
    let n = nums.len();
    if n == 0 {
        return if target == 0 { 0 } else { -1 };
    }

    // 1. Calculate total XOR X
    let total_xor: i64 = nums.iter().fold(0, |acc, &x| acc ^ x);

    // 2. Calculate required XOR sum T' for the removed subset R
    let required_xor_R = total_xor ^ target;

    // Maximum possible XOR value is < 2^14 since nums[i] <= 10^4.
    const MAX_XOR: usize = 1 << 14;
    const INF_SIZE: i64 = 41; // N <= 40, so N+1 serves as infinity

    // Helper function to build the map (vector) for a segment
    // map[x] stores the minimum size of a subset R_segment such that XOR(R_segment) = x.
    let build_map = |segment: &[i64]| -> Vec<i64> {
        let n_seg = segment.len();
        let mut map = vec![INF_SIZE; MAX_XOR];
        map[0] = 0; // Empty set has XOR sum 0 and size 0

        let len = segment.len();
        let num_subsets = 1 << len;

        for i in 0..num_subsets {
            let mut current_xor: i64 = 0;
            let mut current_size: i64 = 0;

            for j in 0..len {
                if (i >> j) & 1 == 1 {
                    current_xor ^= segment[j];
                    current_size += 1;
                }
            }

            let xor_idx = current_xor as usize;
            map[xor_idx] = min(map[xor_idx], current_size);
        }
        map
    };

    // 3. Split nums and build maps
    let n_a = n / 2;
    let a = &nums[0..n_a];
    let b = &nums[n_a..n];

    let map_a = build_map(a);
    let map_b = build_map(b);

    // 4. Find Minimum Removal Size
    let mut min_removals = INF_SIZE;

    // Iterate over all possible XOR sums from the first half (A)
    for xor_a in 0..MAX_XOR {
        let size_a = map_a[xor_a];
